const items = $input.all();
const now = new Date();
const results = [];

for (const item of items) {
  const citaDate = new Date(item.json.fecha + ' ' + item.json.hora);
  const diffHours = (citaDate - now) / (1000 * 60 * 60);

  if (diffHours > 22 && diffHours <= 26) {
    results.push({
      ...item.json,
      tipo_recordatorio: '24h',
      diff_hours: diffHours
    });
  } else if (diffHours > 1 && diffHours <= 3) {
    results.push({
      ...item.json,
      tipo_recordatorio: '2h',
      diff_hours: diffHours
    });
  }
}

return results.map(r => ({ json: r }));
